import React, { useState, useEffect } from 'react';
import {
  Card,
  CardContent,
  Typography,
  Button,
  Grid,
  IconButton,
  Divider,
  Box,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import RemoveIcon from '@mui/icons-material/Remove';

export default function POS({ outletId }) {
  const [products, setProducts] = useState([]);
  const [cart, setCart] = useState([]);

  useEffect(() => {
    const fetchOutletProducts = async () => {
      setProducts([
        {
          outlet_products_id: 1,
          name: 'Latte',
          price: 250,
          stock_quantity: 15,
        },
        {
          outlet_products_id: 2,
          name: 'Espresso',
          price: 180,
          stock_quantity: 5,
        },
        {
          outlet_products_id: 3,
          name: 'Cheesecake',
          price: 300,
          stock_quantity: 2,
        },
      ]);
    };
    fetchOutletProducts();
  }, [outletId]);

  const addToCart = (product) => {
    const existingItem = cart.find(
      (item) => item.outlet_products_id === product.outlet_products_id
    );
    const currentQty = existingItem ? existingItem.qty : 0;

    if (currentQty + 1 > product.stock_quantity) {
      alert(`Cannot add more! Only ${product.stock_quantity} in stock.`);
      return;
    }

    if (existingItem) {
      setCart(
        cart.map((item) =>
          item.outlet_products_id === product.outlet_products_id
            ? { ...item, qty: item.qty + 1 }
            : item
        )
      );
    } else {
      setCart([...cart, { ...product, qty: 1 }]);
    }
  };

  const removeFromCart = (id) => {
    const existingItem = cart.find((item) => item.outlet_products_id === id);
    if (existingItem.qty === 1) {
      setCart(cart.filter((item) => item.outlet_products_id !== id));
    } else {
      setCart(
        cart.map((item) =>
          item.outlet_products_id === id ? { ...item, qty: item.qty - 1 } : item
        )
      );
    }
  };

  const cartTotal = cart.reduce((sum, item) => sum + item.price * item.qty, 0);

  const handleCheckout = () => {
    const payload = {
      outlet_id: outletId,
      user_id: 1,
      items: cart.map((item) => ({
        outlet_products_id: item.outlet_products_id,
        qty: item.qty,
        unit_price: item.price,
      })),
    };
    console.log('API Call: POST /api/sales', payload);
    alert(`Sale Completed! Total: ৳${cartTotal}`);
    setCart([]);
  };

  return (
    <Box sx={{ padding: '24px' }}>
      <Grid container spacing={4}>
        {/* প্রোডাক্ট গ্রিড */}
        <Grid item xs={12} md={8}>
          <Typography
            variant="h5"
            sx={{ fontWeight: 'bold', marginBottom: '24px' }}
          >
            Menu Items
          </Typography>
          <Grid container spacing={3}>
            {products.map((product) => (
              <Grid item xs={12} sm={6} md={4} key={product.outlet_products_id}>
                <Card
                  variant="outlined"
                  sx={{
                    transition: '0.2s',
                    '&:hover': { boxShadow: '0 4px 12px rgba(0,0,0,0.1)' },
                  }}
                >
                  <CardContent
                    sx={{
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      padding: '24px',
                    }}
                  >
                    <Typography
                      variant="h6"
                      sx={{ fontWeight: '600', textAlign: 'center' }}
                    >
                      {product.name}
                    </Typography>
                    <Typography color="text.secondary">
                      ৳{product.price}
                    </Typography>
                    <Typography
                      variant="body2"
                      sx={{
                        marginTop: '8px',
                        marginBottom: '16px',
                        fontWeight:
                          product.stock_quantity < 5 ? 'bold' : 'normal',
                        color: product.stock_quantity < 5 ? '#d32f2f' : '#666',
                      }}
                    >
                      Stock: {product.stock_quantity}
                    </Typography>
                    <Button
                      variant="outlined"
                      fullWidth
                      disabled={product.stock_quantity === 0}
                      onClick={() => addToCart(product)}
                    >
                      Add to Cart
                    </Button>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Grid>

        {/* কার্ট এবং চেকআউট */}
        <Grid item xs={12} md={4}>
          <Card
            variant="outlined"
            sx={{
              position: 'sticky',
              top: '24px',
              boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
              backgroundColor: '#fff',
            }}
          >
            <CardContent
              sx={{ display: 'flex', flexDirection: 'column', height: '80vh' }}
            >
              <Typography
                variant="h5"
                sx={{ fontWeight: 'bold', marginBottom: '16px' }}
              >
                Current Sale
              </Typography>
              <Divider sx={{ marginBottom: '16px' }} />

              <Box sx={{ flexGrow: 1, overflowY: 'auto', paddingRight: '8px' }}>
                {cart.length === 0 ? (
                  <Typography
                    color="text.secondary"
                    sx={{ textAlign: 'center', marginTop: '40px' }}
                  >
                    Cart is empty
                  </Typography>
                ) : (
                  cart.map((item) => (
                    <Box
                      key={item.outlet_products_id}
                      sx={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        marginBottom: '16px',
                      }}
                    >
                      <Box sx={{ flex: 1 }}>
                        <Typography
                          variant="subtitle1"
                          sx={{ fontWeight: '600' }}
                        >
                          {item.name}
                        </Typography>
                        <Typography variant="body2" color="text.secondary">
                          ৳{item.price} x {item.qty}
                        </Typography>
                      </Box>
                      <Box
                        sx={{
                          display: 'flex',
                          alignItems: 'center',
                          backgroundColor: '#f5f5f5',
                          borderRadius: '4px',
                        }}
                      >
                        <IconButton
                          size="small"
                          onClick={() =>
                            removeFromCart(item.outlet_products_id)
                          }
                        >
                          <RemoveIcon fontSize="small" />
                        </IconButton>
                        <Typography
                          sx={{ padding: '0 8px', fontWeight: 'bold' }}
                        >
                          {item.qty}
                        </Typography>
                        <IconButton
                          size="small"
                          onClick={() => addToCart(item)}
                        >
                          <AddIcon fontSize="small" />
                        </IconButton>
                      </Box>
                    </Box>
                  ))
                )}
              </Box>

              <Divider sx={{ marginY: '16px' }} />
              <Box
                sx={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  marginBottom: '24px',
                }}
              >
                <Typography variant="h6" sx={{ fontWeight: 'bold' }}>
                  Total:
                </Typography>
                <Typography
                  variant="h5"
                  sx={{ fontWeight: 'bold', color: '#2e7d32' }}
                >
                  ৳{cartTotal}
                </Typography>
              </Box>

              <Button
                variant="contained"
                color="success"
                size="large"
                fullWidth
                disabled={cart.length === 0}
                onClick={handleCheckout}
                sx={{
                  paddingY: '12px',
                  fontWeight: 'bold',
                  fontSize: '1.1rem',
                }}
              >
                Checkout & Pay
              </Button>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
}
